from collections import Counter, defaultdict

def get_index_statistics(
    index_path: str
) -> Dict[str, Any]:
    """Get comprehensive statistics about a LEANN index.

Args:
    index_path: Path to the LEANN index file

Returns:
    Dictionary containing:
    {
        "total_passages": total number of passages,
        "metadata_fields": list of unique metadata field names,
        "field_value_counts": dictionary of field value counts
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""
    try:
        # Create LeannSearcher instance
        searcher = LeannSearcher(index_path)

        # Get total passage count
        total_passages = searcher.get_passage_count()

        # Get all metadata fields from passages
        metadata_fields = set()
        passage_manager = PassageManager(index_path)
        for passage_id in passage_manager.passage_files.keys():
            passage_data = passage_manager.get_passage(passage_id)
            if 'metadata' in passage_data:
                metadata_fields.update(passage_data['metadata'].keys())

        # Count values for each field
        field_value_counts = {}
        for passage_id in passage_manager.passage_files.keys():
            passage_data = passage_manager.get_passage(passage_id)
            if 'metadata' in passage_data:
                for field_name, field_value in passage_data['metadata'].items():
                    if field_name in field_value_counts:
                        field_value_counts[field_name][field_value] = field_value_counts[field_name].get(field_value, 0) + 1
                    else:
                        field_value_counts[field_name] = {field_value: 1}

        return {
            "total_passages": total_passages,
            "metadata_fields": list(metadata_fields),
            "field_value_counts": field_value_counts
        }

    except FileNotFoundError as e:
        raise FileNotFoundError(f"Index metadata file not found at {index_path}: {e}")

def analyze_index_coverage(index_path: str, required_fields: List[str]) -> Dict[str, Any]:
    """Analyze how well an index covers required metadata fields.

Args:
    index_path: Path to the LEANN index file
    required_fields: List of metadata field names that should be present

Returns:
    Dictionary containing:
    {
        "coverage_percentage": percentage of passages that have all required fields,
        "field_coverage": dictionary mapping field name to coverage percentage,
        "missing_fields": list of required fields not found in any passage
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""
    try:
        # Create LeannSearcher instance
        searcher = LeannSearcher(index_path)

        # Get total passage count
        total_passages = searcher.get_passage_count()

        # Check field presence in each passage
        field_presence = defaultdict(Counter)
        all_fields_present = []

        passage_manager = PassageManager(index_path)
        for passage_id in passage_manager.passage_files.keys():
            has_all_required = True
            field_coverage = {}

            passage_data = passage_manager.get_passage(passage_id)
            if 'metadata' in passage_data:
                for field in required_fields:
                    if field in passage_data['metadata']:
                        field_coverage[field] = True
                        field_presence[field][True] += 1
                    else:
                        field_coverage[field] = False
                        field_presence[field][False] += 1
                        has_all_required = False

            if has_all_required:
                all_fields_present.append(passage_id)

        # Calculate coverage metrics
        coverage_percentage = (len(all_fields_present) / total_passages) * 100 if total_passages > 0 else 0

        field_coverage_percentages = {}
        for field in required_fields:
            total_for_field = field_presence[field][True] + field_presence[field][False]
            if total_for_field > 0:
                field_coverage_percentages[field] = (field_presence[field][True] / total_for_field) * 100
            else:
                field_coverage_percentages[field] = 0

        # Identify missing fields
        missing_fields = [field for field in required_fields if field_presence[field][True] == 0]

        return {
            "coverage_percentage": coverage_percentage,
            "field_coverage": field_coverage_percentages,
            "missing_fields": missing_fields
        }

    except FileNotFoundError as e:
        raise FileNotFoundError(f"Index metadata file not found at {index_path}: {e}")
